const response = $input.item.json.output || $input.item.json;

// Handle both string and object responses
const responseText = typeof response === 'string' ? response : JSON.stringify(response);

try {
  // Try to extract JSON array from the response
  const jsonMatch = responseText.match(/\[[\s\S]*\]/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);
    return {
      json: {
        clips: Array.isArray(parsed) ? parsed : [parsed],
        batchIndex: $input.item.json.batchIndex
      }
    };
  } else {
    // If no JSON found, return empty array
    return {
      json: {
        clips: [],
        batchIndex: $input.item.json.batchIndex
      }
    };
  }
} catch (e) {
  // Log error and return empty
  console.error('Parse error:', e.message);
  return {
    json: {
      clips: [],
      error: e.message,
      batchIndex: $input.item.json.batchIndex
    }
  };
}

const transcript = $input.item.json;
const textToSplit = typeof transcript === 'string' ? transcript : transcript.text || JSON.stringify(transcript);

const chunkSize = 3000;
const chunks = [];
const batchSize = 18; // Process 5 chunks together per AI call
const batches = [];

// Create individual chunks
for (let i = 0; i < textToSplit.length; i += chunkSize) {
  chunks.push({
    text: textToSplit.slice(i, i + chunkSize),
    index: Math.floor(i / chunkSize)
  });
}

// Group chunks into batches of 5
for (let i = 0; i < chunks.length; i += batchSize) {
  const batch = chunks.slice(i, i + batchSize);
  const combinedText = batch.map(c => c.text).join('\n\n[CHUNK BREAK]\n\n');

  batches.push({
    text: combinedText,
    chunkIndices: batch.map(c => c.index),
    batchIndex: Math.floor(i / batchSize)
  });
}

return batches.map(batch => ({
  json: batch
}));

// FIXED - Uses "clips" field from your Parse AI Output
const allClips = [];
let totalClipsCount = 0;

for (const item of $input.all()) {
  // FIXED: item.json.clips instead of item.json.output
  const clips = item.json.clips || [];
  allClips.push(...clips);

  if (clips.length > 0) {
    totalClipsCount += clips.length;
  }
}

// Remove duplicates by clip text
const uniqueClips = allClips.filter((clip, index, self) => 
  index === self.findIndex(c => c.clip === clip.clip)
);

return [{
  json: {
    output: uniqueClips,
    totalClips: uniqueClips.length,
    rawTotal: totalClipsCount
  }
}];

// 1. Get configuration data
const formData = $('Check clips number').first()?.json || {};
const numClipsWanted = parseInt(formData["How many of them"]) || 3;

// 2. Collect ALL items from the previous node
const allInputs = $input.all();
let allClips = [];

for (const item of allInputs) {
  // Check if 'output' exists and is an array
  if (item.json.output && Array.isArray(item.json.output)) {
    allClips.push(...item.json.output);
  } 
  // If the previous node outputted them as flat items (no 'output' wrapper)
  else if (item.json.clip) {
    allClips.push(item.json);
  }
}

// 3. Remove duplicates
const uniqueClips = allClips.filter((clip, index, self) => 
  index === self.findIndex(c => c.clip === clip.clip)
);

// 4. Sort and Slice
const topClips = uniqueClips
  .sort((a, b) => {
    const scoreA = (a.reason === 'Inspirational' ? 10 : 5);
    const scoreB = (b.reason === 'Inspirational' ? 10 : 5);
    return scoreB - scoreA;
  })
  .slice(0, numClipsWanted);

// 5. RETURN A SINGLE OBJECT named "output"
return {
    output: topClips, // This changes the UI label to 'output [0]', 'output [1]', etc.
    numClipsWanted: numClipsWanted,
    totalAvailable: uniqueClips.length,
    totalRaw: allClips.length,
    message: `✅ FINAL: ${topClips.length}/${numClipsWanted} clips ready for NCA Toolkit`
};
